import type { ImageViewerProps } from './types';
import { useCssScope } from '../config-provider/hooks';
import { useImageViewerTransform } from './useImageViewerTransform';
import { useImageViewerImages } from './useImageViewerImages';
import { useImageViewerVisible } from './useImageViewerVisible';

export const useImageViewer = (props: ImageViewerProps) => {
  const { images, toolbar, plugins, visible } = props;

  const rootCssScope = useCssScope('image__viewer');

  const { state: useImageViewerImagesState } = useImageViewerImages(props);

  const { state: useImageViewerTransformState } = useImageViewerTransform(props);

  const { state: useImageViewerVisibleState } = useImageViewerVisible({ visible });

  return {
    // props
    images,
    toolbar,
    plugins,
    // css
    rootCssScope,
    // images index
    ...useImageViewerImagesState,
    // transform
    ...useImageViewerTransformState,
    // image visible
    ...useImageViewerVisibleState,
  };
};

export type ImageViewerContextProps = ReturnType<typeof useImageViewer>;
